const raw = $('Supabase Fetch').item.json.master_profile;
let profile = null;
try { profile = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { profile = null; }

const missing = [];
const addMissing = (label) => { if (!missing.includes(label)) missing.push(label); };
const hasProfile = profile && typeof profile === 'object';

if (!hasProfile) {
  addMissing('your resume data');
} else {
  if (!profile.name || !String(profile.name).trim()) addMissing('your full name');
  const contact = profile.contact || {};
  if (!contact.email && !contact.phone) addMissing('a contact email or phone number');
  if (!profile.summary || !String(profile.summary).trim()) addMissing('a short professional summary');
  const hasSkills = Array.isArray(profile.skills) && profile.skills.some((s) => {
    const items = Array.isArray(s?.items) ? s.items.join(', ') : (s?.items ?? s?.skills);
    return items && String(items).trim();
  });
  if (!hasSkills) addMissing('your key skills');
  if (!Array.isArray(profile.education) || profile.education.length === 0) addMissing('your education details');
  if (!Array.isArray(profile.work_experience) || profile.work_experience.length === 0) addMissing('your work experience');
  if (!Array.isArray(profile.projects) || profile.projects.length === 0) addMissing('your projects');
}

const isSufficient = missing.length === 0;
let prompt = '';
if (!isSufficient) {
  if (!hasProfile) {
    prompt = 'Your profile is currently empty. Please upload your resume PDF or send your professional details (starting with your full name) to establish your baseline profile.';
  } else {
    prompt = 'Your profile is incomplete. Please provide your ' + missing[0] + ' next to complete your profile. You can paste the text here or upload your resume PDF.';
  }
}

return [{ json: { ...$input.item.json, profile_status: { isSufficient, missing, prompt } } }];

const raw = $input.item.json.master_profile
  ?? $('Supabase Fetch').item.json.master_profile;

if (!raw) return [{ json: { text: "📭 No profile found. Send me your resume PDF or tell me about yourself!" } }];

let p;
try { p = typeof raw === 'string' ? JSON.parse(raw) : raw; }
catch(e) { return [{ json: { text: "❌ Could not read profile data. Try uploading your resume PDF again." } }]; }

if (!p || typeof p !== 'object') return [{ json: { text: "📭 No profile found. Send me your resume PDF!" } }];

const hasData = p.name || p.summary || p.tagline
  || (p.skills && p.skills.length > 0)
  || (p.work_experience && p.work_experience.length > 0)
  || (p.education && p.education.length > 0)
  || (p.projects && p.projects.length > 0)
  || (p.certifications && p.certifications.length > 0)
  || (p.contact && (p.contact.email || p.contact.phone));

if (!hasData) return [{ json: { text: "📭 Your profile appears empty. Please upload your resume PDF or tell me your details!" } }];

let msg = `*Master Resume Profile*\n━━━━━━━━━━━━━━━━━━━━\n\n`;

if (p.name) msg += `*${p.name}*\n`;
if (p.tagline) msg += `_${p.tagline}_\n`;
if (p.name || p.tagline) msg += `\n`;

if (p.contact) {
  const c = p.contact;
  const hasContact = c.email || c.phone || c.linkedin_display || c.linkedin_url || c.github_display || c.github_url || c.portfolio_display || c.portfolio_url;
  if (hasContact) {
    msg += `*Contact Details*\n`;
    if (c.email) msg += `  Email: ${c.email}\n`;
    if (c.phone) msg += `  Phone: ${c.phone}\n`;
    if (c.linkedin_display || c.linkedin_url) msg += `  LinkedIn: ${c.linkedin_display || c.linkedin_url}\n`;
    if (c.github_display || c.github_url) msg += `  GitHub: ${c.github_display || c.github_url}\n`;
    if (c.portfolio_display || c.portfolio_url) msg += `  Portfolio: ${c.portfolio_display || c.portfolio_url}\n`;
    msg += `\n`;
  }
}
if (p.summary) msg += `*Professional Summary*\n${p.summary}\n\n`;

if (p.education && p.education.length > 0) {
  msg += `*Education*\n`;
  p.education.forEach(e => {
    msg += `    - *${e.degree}*\n    ${e.institution}\n`;
    if (e.score) msg += `    Score: ${e.score}\n`;
    if (e.year) msg += `    Year: ${e.year}\n`;
  });
  msg += `\n`;
}

if (p.work_experience && p.work_experience.length > 0) {
  msg += `*Work Experience*\n`;
  p.work_experience.forEach(w => {
    msg += `\n  *${w.title}* at ${w.company}`;
    if (w.location) msg += `, ${w.location}`;
    msg += `\n`;
    if (w.start_date) msg += `  _${w.start_date}${w.end_date ? ' – ' + w.end_date : ' – Present'}_\n`;
    if (w.bullet_points && w.bullet_points.length > 0)
      w.bullet_points.forEach(b => msg += `        - ${b}\n`);
  });
  msg += `\n`;
}

if (p.projects && p.projects.length > 0) {
  msg += `*Projects*\n`;
  p.projects.forEach(proj => {
    msg += `\n  *${proj.name}*\n`;
    if (proj.tech_stack) msg += `  _${proj.tech_stack}_\n`;
    if (proj.duration) msg += `  _${proj.duration}_\n`;
    if (proj.link_display || proj.link_url) msg += `  🔗 ${proj.link_display || proj.link_url}\n`;
    if (proj.bullet_points && proj.bullet_points.length > 0)
      proj.bullet_points.forEach(b => msg += `        - ${b}\n`);
  });
  msg += `\n`;
}

if (p.skills && p.skills.length > 0) {
  msg += `*Technical Skills*\n`;
  p.skills.forEach(s => msg += `    - *${s.category || 'Skill'}:* ${s.items || s}\n`);
  msg += `\n`;
}

if (p.certifications && p.certifications.length > 0) {
  msg += `*Certifications*\n`;
  p.certifications.forEach(cert => {
    msg += `    - *${cert.name}*\n    ${cert.issuer}`;
    if (cert.year) msg += ` (${cert.year})`;
    msg += `\n`;
  });
  msg += `\n`;
}

if (msg.length <= 4096) return [{ json: { text: msg, isLast: true } }];
const chunks = []; let current = '';
for (const line of msg.split('\n')) {
  if ((current + line + '\n').length > 4000) { chunks.push(current.trim()); current = line + '\n'; }
  else current += line + '\n';
}
if (current.trim()) chunks.push(current.trim());
return chunks.map((text, index) => ({ json: { text, isLast: index === chunks.length - 1 } }));

const msg = $('Telegram Trigger').item.json.callback_query ? $('Telegram Trigger').item.json.callback_query.data : ($('Telegram Trigger').item.json.message.text || '');
const isOptimized = msg.startsWith('/downloadOptimized');
const rawTailored = $('Supabase Fetch').item.json.tailored_profile;
const rawMaster = $('Supabase Fetch').item.json.master_profile;
const rawProfile = isOptimized ? rawTailored : rawMaster;

if (!rawProfile) {
  return [{
    json: {
      text: isOptimized
        ? "📭 No optimized resume yet. Use \`/optimize [paste JD here]\` to create one!"
        : "📭 No profile found. Please upload your resume PDF first!"
    }
  }];
}
const p = typeof rawProfile === 'string' ? JSON.parse(rawProfile) : rawProfile;

function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/([&%$#{}])/g, '\\$1')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}')
    .replace(/_/g, '\\_');
}

const c = p.contact || {};

let eduBlock = '';
(p.education || []).forEach(e => {
  eduBlock += `  ${esc(e.degree)} & ${esc(e.institution)} & ${esc(e.score)} & ${esc(e.year)} \\\\\n  \\hline\n`;
});

let expBlock = '';
(p.work_experience || []).forEach(w => {
  expBlock += `  \\resumeSubheading{${esc(w.title)}}{${esc(w.location)}}{${esc(w.company)}}{${esc(w.start_date)} -- ${esc(w.end_date || 'Present')}}\n`;
  expBlock += `  \\resumeItemListStart\n`;
  (w.bullet_points || []).forEach(b => { expBlock += `    \\item {${esc(b)}}\n`; });
  expBlock += `  \\resumeItemListEnd\n`;
});

let projBlock = '';
(p.projects || []).forEach(proj => {
  const lTex = proj.link_url ? `\\href{${esc(proj.link_url)}}{${esc(proj.link_display || 'Link')}}` : '';
  projBlock += `  \\resumeProject{${esc(proj.name)}}{${esc(proj.tech_stack)}}{${esc(proj.duration)}}{${lTex}}\n`;
  projBlock += `  \\resumeItemListStart\n`;
  (proj.bullet_points || []).forEach(b => { projBlock += `    \\item {${esc(b)}}\n`; });
  projBlock += `  \\resumeItemListEnd\n`;
});

let skillBlock = '';
(p.skills || []).forEach(s => {
  let items = '';
  if (Array.isArray(s.items)) items = s.items.join(', ');
  else if (typeof s.items === 'string') items = s.items;
  else if (s.skills) items = Array.isArray(s.skills) ? s.skills.join(', ') : s.skills;
  if (!items || !items.trim()) return;
  const cat = s.category || s.name || 'Skills';
  skillBlock += `  \\resumeSubItem{${esc(cat)}}{${esc(items)}}\n`;
});

let certBlock = '';
(p.certifications || []).forEach(cert => {
  certBlock += `  \\resumePOR{${esc(cert.issuer)}}{${esc(cert.name)}}{${esc(cert.year)}}\n`;
});

const tex = `\\documentclass[a4paper,11pt]{article}
\\usepackage{latexsym}
\\usepackage{xcolor}
\\usepackage{float}
\\usepackage{ragged2e}
\\usepackage[empty]{fullpage}
\\usepackage{wrapfig}
\\usepackage{tabularx}
\\usepackage{titlesec}
\\usepackage{geometry}
\\usepackage{marvosym}
\\usepackage{verbatim}
\\usepackage{enumitem}
\\usepackage[hidelinks]{hyperref}
\\usepackage{fancyhdr}
\\usepackage{multicol}
\\usepackage{graphicx}
\\usepackage{cfr-lm}
\\usepackage[T1]{fontenc}
\\setlength{\\multicolsep}{0pt}
\\pagestyle{fancy}
\\fancyhf{}
\\fancyfoot{}
\\renewcommand{\\headrulewidth}{0pt}
\\renewcommand{\\footrulewidth}{0pt}
\\geometry{left=1.4cm, top=0.8cm, right=1.2cm, bottom=1cm}
\\usepackage[most]{tcolorbox}
\\tcbset{frame code={} center title, left=0pt, right=0pt, top=0pt, bottom=0pt, colback=gray!20, colframe=white, width=\\dimexpr\\textwidth\\relax, enlarge left by=-2mm, boxsep=4pt, arc=0pt, outer arc=0pt}
\\urlstyle{same}
\\raggedright
\\setlength{\\tabcolsep}{0in}
\\titleformat{\\section}{\\vspace{-4pt}\\scshape\\raggedright\\large}{}{0em}{}[\\color{black}\\titlerule \\vspace{-7pt}]
\\newcommand{\\resumeItem}[2]{\\item{\\textbf{#1}{: #2 \\vspace{-0.5mm}}}}
\\newcommand{\\resumePOR}[3]{\\vspace{0.5mm}\\item\\begin{tabular*}{0.97\\textwidth}[t]{l@{\\extracolsep{\\fill}}r}\\textbf{#1}: #2 & \\textit{\\small{#3}}\\end{tabular*}\\vspace{-2mm}}
\\newcommand{\\resumeSubheading}[4]{\\vspace{0.5mm}\\item\\begin{tabular*}{0.98\\textwidth}[t]{l@{\\extracolsep{\\fill}}r}\\textbf{#1} & \\textit{\\footnotesize{#4}} \\\\ \\textit{\\footnotesize{#3}} & \\footnotesize{#2}\\\\\\end{tabular*}\\vspace{-2.4mm}}
\\newcommand{\\resumeProject}[4]{\\vspace{0.5mm}\\item\\begin{tabular*}{0.98\\textwidth}[t]{l@{\\extracolsep{\\fill}}r}\\textbf{#1} & \\textit{\\footnotesize{#3}} \\\\ \\footnotesize{\\textit{#2}} & \\footnotesize{#4}\\end{tabular*}\\vspace{-2.4mm}}
\\newcommand{\\resumeSubItem}[2]{\\resumeItem{#1}{#2}\\vspace{-4pt}}
\\renewcommand{\\labelitemi}{$\\vcenter{\\hbox{\\tiny$\\bullet$}}$}
\\newcommand{\\resumeSubHeadingListStart}{\\begin{itemize}[leftmargin=*,labelsep=0mm]}
\\newcommand{\\resumeHeadingSkillStart}{\\begin{itemize}[leftmargin=*,itemsep=1.7mm, rightmargin=2ex]}
\\newcommand{\\resumeItemListStart}{\\begin{justify}\\begin{itemize}[leftmargin=3ex, rightmargin=2ex, noitemsep,labelsep=1.2mm,itemsep=0mm]\\small}
\\newcommand{\\resumeSubHeadingListEnd}{\\end{itemize}\\vspace{2mm}}
\\newcommand{\\resumeHeadingSkillEnd}{\\end{itemize}\\vspace{-2mm}}
\\newcommand{\\resumeItemListEnd}{\\end{itemize}\\end{justify}\\vspace{-2mm}}
\\newcolumntype{L}{>{\\raggedright\\arraybackslash}X}
\\newcolumntype{R}{>{\\raggedleft\\arraybackslash}X}
\\newcolumntype{C}{>{\\centering\\arraybackslash}X}

\\begin{document}
\\fontfamily{cmr}\\selectfont

\\begin{tabular*}{\\textwidth}{l@{\\extracolsep{\\fill}}r}
  {\\LARGE \\textbf{${esc(p.name)}}} & \\href{mailto:${esc(c.email)}}{${esc(c.email)}} \\\\
  \\textit{${esc(p.tagline)}} & ${esc(c.phone)} \\\\
  \\href{${esc(c.linkedin_url)}}{LinkedIn: ${esc(c.linkedin_display)}} & \\href{${esc(c.github_url)}}{GitHub: ${esc(c.github_display)}} \\\\
  \\href{${esc(c.portfolio_url)}}{Portfolio: ${esc(c.portfolio_display)}} & \\\\
\\end{tabular*}

\\section{Profile Summary}
\\vspace{1mm}
\\small{${esc(p.summary)}}
\\vspace{1mm}

\\section{Education}
\\setlength{\\tabcolsep}{5pt}
{\\small \\begin{tabularx}{\\linewidth}{|c|C|c|c|}
  \\hline
  \\textbf{Degree/Certificate} & \\textbf{Institute/Board} & \\textbf{Score} & \\textbf{Year}\\\\
  \\hline
${eduBlock}\\end{tabularx}}
\\vspace{2mm}

\\section{Experience}
\\resumeSubHeadingListStart
${expBlock}\\resumeSubHeadingListEnd
\\vspace{-5.5mm}

\\section{Projects}
\\resumeSubHeadingListStart
${projBlock}\\resumeSubHeadingListEnd
\\vspace{-5.5mm}

\\section{Technical Skills}
\\resumeHeadingSkillStart
${skillBlock}\\resumeHeadingSkillEnd

\\section{Certifications}
\\vspace{-0.2mm}
\\resumeSubHeadingListStart
${certBlock}\\resumeSubHeadingListEnd

\\end{document}`;

return [{
  json: { success: true, tex_b64: Buffer.from(tex).toString('base64') },
  binary: {
    tex_file: {
      data: Buffer.from(tex).toString('base64'),
      mimeType: 'application/x-tex',
      fileName: `resume_${($('Telegram Trigger').item.json.callback_query ? $('Telegram Trigger').item.json.callback_query.message.chat.id : $('Telegram Trigger').item.json.message.chat.id)}.tex`
    }
  }
}];

const b64 = $input.item.json.stdout.trim();
const chatId = ($('Telegram Trigger').item.json.callback_query ? $('Telegram Trigger').item.json.callback_query.message.chat.id : $('Telegram Trigger').item.json.message.chat.id);
return [{
  json: { success: true },
  binary: {
    pdf_doc: {
      data: b64,
      mimeType: 'application/pdf',
      fileName: `resume_${chatId}.pdf`
    }
  }
}];

let rawText = $input.item.json.output || "";
let parsed = {};
try {
  let cleaned = rawText.replace(/```json|```/gi, "").trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) cleaned = jsonMatch[0];
  parsed = JSON.parse(cleaned);
  if (typeof parsed.profile_updated === "string") parsed.profile_updated = parsed.profile_updated.toLowerCase() === "true";
  if (parsed.profile_updated === undefined) parsed.profile_updated = !!parsed.master_profile;

  const existingRow = $("Supabase Fetch").item.json;
  const isNewUser = !existingRow || !existingRow.telegram_id;
  const hasProfileData = parsed.master_profile && typeof parsed.master_profile === "object" && Object.keys(parsed.master_profile).length > 0;
  if (isNewUser && hasProfileData) parsed.profile_updated = true;
} catch (e) {
  parsed = { chat_reply: "Sorry, I had trouble parsing that. Could you try again?", profile_updated: false, master_profile: null };
}

const buildStatus = (profile) => {
  const missing = [];
  const addMissing = (label) => { if (!missing.includes(label)) missing.push(label); };
  const hasProfile = profile && typeof profile === "object";

  if (!hasProfile) {
    addMissing("your resume data");
  } else {
    if (!profile.name || !String(profile.name).trim()) addMissing("your full name");
    const contact = profile.contact || {};
    if (!contact.email && !contact.phone) addMissing("a contact email or phone number");
    if (!profile.summary || !String(profile.summary).trim()) addMissing("a short professional summary");
    const hasSkills = Array.isArray(profile.skills) && profile.skills.some((s) => {
      const items = Array.isArray(s?.items) ? s.items.join(", ") : (s?.items ?? s?.skills);
      return items && String(items).trim();
    });
    if (!hasSkills) addMissing("your key skills");
    if (!Array.isArray(profile.education) || profile.education.length === 0) addMissing("your education details");
    if (!Array.isArray(profile.work_experience) || profile.work_experience.length === 0) addMissing("your work experience");
    if (!Array.isArray(profile.projects) || profile.projects.length === 0) addMissing("your projects");
  }

  const isSufficient = missing.length === 0;
  let prompt = "";
  if (!isSufficient) {
    if (!hasProfile) {
      prompt = "Your profile is currently empty. Please upload your resume PDF or send your professional details (starting with your full name) to establish your baseline profile.";
    } else {
      prompt = "Your profile is incomplete. Please provide your " + missing[0] + " next to complete your profile. You can paste the text here or upload your resume PDF.";
    }
  }

  return { isSufficient, missing, prompt };
};

const rawProfile = parsed.master_profile ?? $("Supabase Fetch").item.json.master_profile;
let profile = null;
try { profile = typeof rawProfile === "string" ? JSON.parse(rawProfile) : rawProfile; } catch (e) { profile = null; }

const profile_status = buildStatus(profile);
parsed.profile_status = profile_status;

if (profile_status.prompt) {
  parsed.chat_reply = parsed.chat_reply ? parsed.chat_reply + "\n\n" + profile_status.prompt : profile_status.prompt;
}

return [{ json: parsed }];

const msg = $('Telegram Trigger').item.json.message.text || '';
const jd = msg.replace(/^\/optimize\s*/i, '').trim();

if (!jd) {
  return [{ json: { promptText: 'The user typed /optimize without a job description. Ask them to paste the full JD directly after /optimize in one message. Example: /optimize [paste JD here]' } }];
}

const rawProfile = $('Supabase Fetch').item.json.master_profile;
if (!rawProfile) {
  return [{ json: { promptText: 'The user has no profile yet. Tell them to upload their resume PDF first before optimizing.' } }];
}

const profile = typeof rawProfile === 'string' ? JSON.parse(rawProfile) : rawProfile;

const promptText = `OPTIMIZE my resume for this Job Description. Remember: COPY my name, contact, education, and certifications EXACTLY. Only rewrite summary, reorder skills, and rephrase bullet points.

MY CURRENT PROFILE:
${JSON.stringify(profile, null, 2)}

TARGET JOB DESCRIPTION:
${jd}`;

return [{ json: { promptText } }];

let rawText = $input.item.json.output || '';
let parsed = {};
try {
  let cleaned = rawText.replace(/```json|```/gi, '').trim();
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (m) cleaned = m[0];
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { chat_reply: "Sorry, I had trouble optimizing your profile. Try again!", tailored_profile: null };
}
return [{ json: parsed }];

const raw = $input.item.json.tailored_profile
  ?? $('Supabase Fetch').item.json.tailored_profile;

if (!raw) return [{ json: { text: "No optimized profile exists" } }];

let p;
try { p = typeof raw === 'string' ? JSON.parse(raw) : raw; }
catch(e) { return [{ json: { text: "❌ Could not read tailored profile. Try running /optimize again." } }]; }

const hasData = p.name || p.summary || p.tagline
  || (p.skills && p.skills.length > 0)
  || (p.work_experience && p.work_experience.length > 0);

if (!hasData) return [{ json: { text: "No optimized profile exists" } }];

let msg = `*Tailored Resume Profile*\n━━━━━━━━━━━━━━━━━━━━\n\n`;

if (p.name) msg += `*${p.name}*\n`;
if (p.tagline) msg += `_${p.tagline}_\n`;
if (p.name || p.tagline) msg += `\n`;

if (p.contact) {
  const c = p.contact;
  const hasContact = c.email || c.phone || c.linkedin_display || c.linkedin_url || c.github_display || c.github_url || c.portfolio_display || c.portfolio_url;
  if (hasContact) {
    msg += `*Contact Details*\n`;
    if (c.email) msg += `  Email: ${c.email}\n`;
    if (c.phone) msg += `  Phone: ${c.phone}\n`;
    if (c.linkedin_display || c.linkedin_url) msg += `  LinkedIn: ${c.linkedin_display || c.linkedin_url}\n`;
    if (c.github_display || c.github_url) msg += `  GitHub: ${c.github_display || c.github_url}\n`;
    if (c.portfolio_display || c.portfolio_url) msg += `  Portfolio: ${c.portfolio_display || c.portfolio_url}\n`;
    msg += `\n`;
  }
}

if (p.summary) msg += `*Professional Summary*\n${p.summary}\n\n`;

if (p.education && p.education.length > 0) {
  msg += `*Education*\n`;
  p.education.forEach(e => {
    msg += `    - *${e.degree}*\n    ${e.institution}\n`;
    if (e.score) msg += `    Score: ${e.score}\n`;
    if (e.year) msg += `    Year: ${e.year}\n`;
  });
  msg += `\n`;
}

if (p.work_experience && p.work_experience.length > 0) {
  msg += `*Work Experience*\n`;
  p.work_experience.forEach(w => {
    msg += `\n  *${w.title}* at ${w.company}`;
    if (w.location) msg += `, ${w.location}`;
    msg += `\n`;
    if (w.start_date) msg += `  _${w.start_date}${w.end_date ? ' – ' + w.end_date : ' – Present'}_\n`;
    if (w.bullet_points && w.bullet_points.length > 0)
      w.bullet_points.forEach(b => msg += `        - ${b}\n`);
  });
  msg += `\n`;
}

if (p.projects && p.projects.length > 0) {
  msg += `*Projects*\n`;
  p.projects.forEach(proj => {
    msg += `\n  *${proj.name}*\n`;
    if (proj.tech_stack) msg += `  _${proj.tech_stack}_\n`;
    if (proj.duration) msg += `  _${proj.duration}_\n`;
    if (proj.link_display || proj.link_url) msg += `  🔗 ${proj.link_display || proj.link_url}\n`;
    if (proj.bullet_points && proj.bullet_points.length > 0)
      proj.bullet_points.forEach(b => msg += `        - ${b}\n`);
  });
  msg += `\n`;
}

if (p.skills && p.skills.length > 0) {
  msg += `*Technical Skills*\n`;
  p.skills.forEach(s => msg += `    - *${s.category || 'Skill'}:* ${s.items || s}\n`);
  msg += `\n`;
}

if (p.certifications && p.certifications.length > 0) {
  msg += `*Certifications*\n`;
  p.certifications.forEach(cert => {
    msg += `    - *${cert.name}*\n    ${cert.issuer}`;
    if (cert.year) msg += ` (${cert.year})`;
    msg += `\n`;
  });
  msg += `\n`;
}

msg += `━━━━━━━━━━━━━━━━━━━━\n_Use the /downloadOptimized command to export your tailored PDF resume._`;

if (msg.length <= 4096) return [{ json: { text: msg, isLast: true } }];
const chunks = []; let current = '';
for (const line of msg.split('\n')) {
  if ((current + line + '\n').length > 4000) { chunks.push(current.trim()); current = line + '\n'; }
  else current += line + '\n';
